"use client"

import { useState } from "react"
import { DashboardLayout } from "@/components/dashboard-layout"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Progress } from "@/components/ui/progress"
import { Badge } from "@/components/ui/badge"
import { Checkbox } from "@/components/ui/checkbox"
import { sampleRoadmap } from "@/lib/sample-data"
import { Calendar, Clock, CheckCircle2 } from "lucide-react"

export default function RoadmapPage() {
  const [tasks, setTasks] = useState(sampleRoadmap)

  const completedTasks = tasks.filter((t) => t.completed).length
  const progress = Math.round((completedTasks / tasks.length) * 100)

  const toggleTask = (taskId: string) => {
    setTasks(tasks.map((t) => (t.id === taskId ? { ...t, completed: !t.completed } : t)))
  }

  return (
    <DashboardLayout>
      <div className="space-y-8">
        {/* Header */}
        <div>
          <h1 className="text-3xl font-bold mb-2">Your Career Roadmap</h1>
          <p className="text-muted-foreground">Follow this structured path to reach your career goals</p>
        </div>

        <Card className="hover:shadow-lg transition-shadow">
          <CardHeader>
            <CardTitle>Overall Progress</CardTitle>
            <CardDescription>Track your journey to achieving your career goals</CardDescription>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <span className="text-sm font-medium">
                  {completedTasks} of {tasks.length} tasks completed
                </span>
                <span className="text-2xl font-bold text-primary animate-pulse">{progress}%</span>
              </div>
              <Progress value={progress} className="h-3" />
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4 pt-4">
                <div className="flex items-center gap-2 bg-secondary/5 p-3 rounded-lg hover:bg-secondary/10 transition-colors">
                  <CheckCircle2 className="w-5 h-5 text-secondary" />
                  <div>
                    <p className="text-sm font-medium">{completedTasks} Completed</p>
                    <p className="text-xs text-muted-foreground">Tasks done</p>
                  </div>
                </div>
                <div className="flex items-center gap-2 bg-primary/5 p-3 rounded-lg hover:bg-primary/10 transition-colors">
                  <Calendar className="w-5 h-5 text-primary" />
                  <div>
                    <p className="text-sm font-medium">{tasks.length - completedTasks} Remaining</p>
                    <p className="text-xs text-muted-foreground">Tasks left</p>
                  </div>
                </div>
                <div className="flex items-center gap-2 bg-accent/5 p-3 rounded-lg hover:bg-accent/10 transition-colors">
                  <Clock className="w-5 h-5 text-accent" />
                  <div>
                    <p className="text-sm font-medium">~8 months</p>
                    <p className="text-xs text-muted-foreground">Estimated time</p>
                  </div>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Roadmap Timeline */}
        <Card>
          <CardHeader>
            <CardTitle>Learning Path</CardTitle>
            <CardDescription>Step-by-step tasks to guide your career development</CardDescription>
          </CardHeader>
          <CardContent>
            <div className="space-y-6">
              {tasks.map((task, index) => (
                <div key={task.id} className="flex items-start gap-4">
                  {/* Timeline Line */}
                  <div className="flex flex-col items-center flex-shrink-0">
                    <div
                      className={`w-10 h-10 rounded-full border-2 flex items-center justify-center font-semibold transition-all ${
                        task.completed
                          ? "bg-secondary text-secondary-foreground border-secondary scale-110"
                          : "bg-background border-border hover:scale-105"
                      }`}
                    >
                      {task.completed ? <CheckCircle2 className="w-5 h-5" /> : index + 1}
                    </div>
                    {index < tasks.length - 1 && <div className="w-0.5 h-16 bg-border my-2" />}
                  </div>

                  <Card
                    className={`flex-1 hover:shadow-md transition-all ${task.completed ? "opacity-75" : "hover:-translate-y-0.5"}`}
                  >
                    <CardContent className="pt-6">
                      <div className="flex items-start justify-between gap-4 mb-3">
                        <div className="flex-1">
                          <div className="flex items-center gap-3 mb-2">
                            <h3 className={`font-semibold text-lg ${task.completed ? "line-through" : ""}`}>
                              {task.title}
                            </h3>
                            <Badge variant="outline" className="text-xs">
                              Week {task.week}
                            </Badge>
                          </div>
                          <p className="text-muted-foreground text-sm mb-3">{task.description}</p>
                          <div className="flex items-center gap-2 text-sm text-muted-foreground">
                            <Clock className="w-4 h-4" />
                            <span>{task.duration}</span>
                          </div>
                        </div>
                      </div>
                      <div className="flex items-center gap-4 pt-3 border-t border-border">
                        <div className="flex items-center gap-2">
                          <Checkbox
                            id={`task-${task.id}`}
                            checked={task.completed}
                            onCheckedChange={() => toggleTask(task.id)}
                          />
                          <label htmlFor={`task-${task.id}`} className="text-sm font-medium cursor-pointer">
                            {task.completed ? "Completed" : "Mark as complete"}
                          </label>
                        </div>
                        {!task.completed && (
                          <Button
                            size="sm"
                            variant="outline"
                            className="ml-auto bg-transparent hover:bg-primary hover:text-primary-foreground transition-colors"
                          >
                            Start Task
                          </Button>
                        )}
                      </div>
                    </CardContent>
                  </Card>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      </div>
    </DashboardLayout>
  )
}
